          var ungrounded = runtimeState.params.answerGenerated && runtimeState.params.qualityMode === 0 && runtimeState.params.searchRun === true;
          return React.createElement(
            'div',
            { style: { marginTop: 14 } },
            React.createElement(
              'div',
              { style: { fontSize: 11, letterSpacing: '0.15em', textTransform: 'uppercase', color: textMuted } },
              'Context Window'
            ),
            React.createElement(
              'div',
              {
                style: {
                  marginTop: 6,
                  height: 10,
                  borderRadius: 999,
                  border: '1px solid ' + panelBorder,
                  overflow: 'hidden',
                  background: 'rgba(255,255,255,0.45)'
                }
              },
              React.createElement('div', {
                style: {
                  width: Math.round(ratio * 100) + '%',
                  height: '100%',
                  background: palette.primary
                }
              })
            ),
            React.createElement(
              'div',
              { style: { marginTop: 6, fontFamily: 'ui-monospace, monospace', fontWeight: 700, color: textPrimary } },
              total + ' / ' + capacity + ' tokens'
            ),
            React.createElement(
              'div',
              {
                style: {
                  marginTop: 10,
                  padding: 12,
                  borderRadius: 12,
                  border: '1px solid ' + panelBorder,
                  background: grounded
                    ? 'rgba(22, 163, 74, 0.12)'
                    : ungrounded
                      ? 'rgba(220, 38, 38, 0.10)'
                      : 'rgba(255,255,255,0.45)',
                  color: textPrimary,
                  lineHeight: 1.25
                }
              },
              React.createElement(
                'div',
                { style: { fontSize: 10, letterSpacing: '0.22em', textTransform: 'uppercase', color: textMuted } },
                'LLM ANSWER'
              ),
              React.createElement(
                'div',
                { style: { marginTop: 6, fontSize: 13 } },
                runtimeState.params.answerGenerated
                  ? grounded
                    ? 'RAG retrieves relevant chunks and uses them as context so the model can answer with cited, checkable evidence.'
                    : 'The model gives a plausible answer, but retrieval may be off—so the response can be unsupported or misleading.'
                  : 'Click “Generate Answer” to produce a response.'
              )
            )
          );
        })()
      )
    )
  );
}

